const rows = $input.all().map(i => i.json);

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));

const pending = rows
  .filter(r => String(r.status || '').toUpperCase() === 'PENDING')
  .slice(0, 75);

const options = pending
  .map(r => {
    const rowId = String(r.row_id || '').trim();
    const title = String(r.pin_title || '').trim();
    const label = `${rowId} — ${title}`.trim();
    return `<option value="${esc(rowId)}">${esc(label).slice(0, 160)}</option>`;
  })
  .join('\n');

const hasOptions = pending.length > 0;

const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>DLH Pinterest Publish</title>
  <style>
    body { font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Arial; margin: 24px; }
    .card { max-width: 760px; border: 1px solid #ddd; border-radius: 12px; padding: 18px; }
    h1 { margin: 0 0 8px; font-size: 20px; }
    p { margin: 0 0 12px; color: #444; line-height: 1.4; }
    select, button { width: 100%; padding: 10px; font-size: 14px; }
    button { margin-top: 12px; background: #F29B30; color: #fff; border: 0; border-radius: 10px; font-weight: 800; cursor: pointer; }
    .muted { font-size: 12px; color: #666; margin-top: 10px; }
    .warn { background: #fff7ed; border: 1px solid #fed7aa; padding: 12px; border-radius: 10px; color: #7c2d12; margin-top: 12px; }
    code { background: #f5f5f5; padding: 2px 6px; border-radius: 6px; }
  </style>
</head>
<body>
  <div class="card">
    <h1>Publish 1 Pinterest Pin (manual)</h1>
    <p>Select exactly one <code>PENDING</code> row. This workflow will publish only what you pick.</p>
    ${hasOptions ? '' : '<div class="warn">No PENDING rows found.</div>'}
    <form method="POST">
      <label for="row_id"><strong>Select pin</strong></label>
      <select id="row_id" name="row_id" required>
        ${hasOptions ? options : '<option value="">(none)</option>'}
      </select>
      <button type="submit" ${hasOptions ? '' : 'disabled'}>Publish selected pin</button>
      <div class="muted">Demo note: manual selection is intentional to match Pinterest guidelines.</div>
    </form>
  </div>
</body>
</html>`;

return [{ json: { html } }];

const FORCE_BOARD_ID = ''; // Optional: set a fixed board_id for the demo

const body = $input.first().json.body || {};
const rowId = String(body.row_id || '').trim();

if (!rowId) {
  return [{ json: { valid: false, row_id: '', status: 'ERROR', pin_id: '', published_date: new Date().toISOString(), pinterest_response: 'No row_id selected' } }];
}

const allRows = $('List Pending Rows (POST)').all().map(i => i.json);
const row = allRows.find(r => String(r.row_id || '').trim() === rowId);

if (!row) {
  return [{ json: { valid: false, row_id: rowId, status: 'ERROR', pin_id: '', published_date: new Date().toISOString(), pinterest_response: 'Selected row not found in pending list' } }];
}

const banned = ['casino', 'viagra'];
const errors = [];
const title = String(row.pin_title ?? '').trim();
const desc = String(row.pin_description ?? '').trim();
const alt = String(row.alt_text ?? '').trim();
const imageUrl = String(row.image_url ?? '').trim();
const boardIdFromRow = String(row.board_id ?? '').trim();
const link = String(row.link ?? '').trim();

const finalBoardId = String(FORCE_BOARD_ID || boardIdFromRow).trim();

if (!String(row.row_id ?? '').trim()) errors.push('row_id missing');
if (!title) errors.push('pin_title missing');
if (title.length > 100) errors.push('pin_title over 100 chars');
if (!desc) errors.push('pin_description empty');
if (desc.length < 100 || desc.length > 500) errors.push('pin_description must be 100-500 chars');
if (!alt) errors.push('alt_text empty');
if (alt.length < 50 || alt.length > 500) errors.push('alt_text must be 50-500 chars');
if (!imageUrl) errors.push('image_url empty');
if (!finalBoardId) errors.push('board_id empty');
if (!link) errors.push('link empty');

const blob = (title + ' ' + desc).toLowerCase();
for (const w of banned) {
  if (blob.includes(w.toLowerCase())) errors.push('blocked term');
}

if (errors.length) {
  return [{
    json: {
      valid: false,
      row_id: row.row_id,
      status: 'ERROR',
      pin_id: '',
      published_date: new Date().toISOString(),
      pinterest_response: 'Validation: ' + errors.join('; ')
    }
  }];
}

return [{
  json: {
    valid: true,
    row_id: row.row_id,
    pinPayload: {
      title,
      description: desc.replace(/\n/g, ' '),
      link,
      alt_text: alt,
      board_id: finalBoardId,
      media_source: { source_type: 'image_url', url: imageUrl }
    }
  }
}];

const row = $('Get Next Pending Row').first().json;
const banned = ['casino', 'viagra'];

const errors = [];
const title = String(row.pin_title ?? '').trim();
const desc = String(row.pin_description ?? '').trim();
const alt = String(row.alt_text ?? '').trim();
const imageUrl = String(row.image_url ?? '').trim();
const boardId = String(row.board_id ?? '').trim();
const link = String(row.link ?? '').trim();

if (!String(row.row_id ?? '').trim()) errors.push('row_id missing');
if (!title) {
  return [{
    json: {
      valid: false,
      row_id: row.row_id,
      status: 'SKIPPED',
      pin_id: '',
      published_date: new Date().toISOString(),
      pinterest_response: 'Skipped: no pin_title'
    }
  }];
}
if (title.length > 100) errors.push('pin_title over 100 chars');
if (!desc) errors.push('pin_description empty');
if (desc.length < 100 || desc.length > 500) errors.push('pin_description must be 100-500 chars');
if (!alt) errors.push('alt_text empty');
if (alt.length < 50 || alt.length > 500) errors.push('alt_text must be 50-500 chars');
if (!imageUrl) errors.push('image_url empty');
if (!boardId) errors.push('board_id empty');
if (!link) errors.push('link empty');

const blob = (title + ' ' + desc).toLowerCase();
for (const w of banned) {
  if (blob.includes(w.toLowerCase())) errors.push('blocked term');
}

if (errors.length) {
  return [{
    json: {
      valid: false,
      row_id: row.row_id,
      status: 'ERROR',
      pin_id: '',
      published_date: new Date().toISOString(),
      pinterest_response: 'Validation: ' + errors.join('; ')
    }
  }];
}

return [{
  json: {
    valid: true,
    row_id: row.row_id,
    pinPayload: {
      title,
      description: desc.replace(/\n/g, ' '),
      link,
      alt_text: alt,
      board_id: boardId,
      media_source: { source_type: 'image_url', url: imageUrl }
    }
  }
}];

const api = $input.first().json;
const row = $('Validate and Build Payload (Selected)').first().json;

if (api && api.id) {
  return [{
    json: {
      row_id: row.row_id,
      status: 'PUBLISHED',
      pin_id: api.id,
      published_date: new Date().toISOString(),
      pinterest_response: JSON.stringify(api).substring(0, 500)
    }
  }];
}

return [{
  json: {
    row_id: row.row_id,
    status: 'ERROR',
    pin_id: '',
    published_date: new Date().toISOString(),
    pinterest_response: JSON.stringify(api || { message: 'Unknown API error' }).substring(0, 500)
  }
}];

const r = $input.first().json || {};
const ok = String(r.status || '') === 'PUBLISHED';
const pinId = String(r.pin_id || '');
const msg = String(r.pinterest_response || '');

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));

const title = ok ? 'Published' : 'Error';
const color = ok ? '#166534' : '#7c2d12';
const bg = ok ? '#f0fdf4' : '#fff7ed';

const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${title}</title>
  <style>
    body{font-family:ui-sans-serif,system-ui,-apple-system,Segoe UI,Roboto,Arial;margin:24px}
    .card{max-width:760px;border:1px solid #ddd;border-radius:12px;padding:18px}
    h1{margin:0 0 10px;font-size:20px}
    .box{background:${bg};border:1px solid #ddd;padding:12px;border-radius:10px;color:${color};line-height:1.5}
    code{background:#f5f5f5;padding:2px 6px;border-radius:6px;word-break:break-all}
    a{color:#F29B30;font-weight:800}
  </style>
</head>
<body>
  <div class="card">
    <h1>${title}</h1>
    <div class="box">
      Row: <code>${esc(r.row_id || '')}</code><br/>
      Status: <code>${esc(r.status || '')}</code>
      ${pinId ? `<br/>Pin ID: <code>${esc(pinId)}</code>` : ''}
    </div>
    ${msg ? `<p style="margin-top:12px;color:#444">${esc(msg).slice(0, 400)}</p>` : ''}
    <p style="margin-top:12px"><a href="/webhook/dlh/pinterest/publish">Publish another (manual)</a></p>
  </div>
</body>
</html>`;

return [{ json: { html } }];
